const items = $input.all();
if (!items || items.length === 0) {
  throw new Error('No data received from Google Sheets. Check the sheet ID, tab name, and permissions.');
}
for (let i = 0; i < items.length; i++) {
  const row = items[i].json;
  const keys = Object.keys(row).filter(k => k !== 'row_number');
  const colA = keys[0];
  const colB = keys[1];
  const colC = keys.length > 2 ? keys[2] : null;
  if (colB && row[colB] && row[colB].toString().toLowerCase().trim() === 'pending' && row[colA] && row[colA].toString().trim()) {
    const topic = row[colA].toString().trim();
    return [{ json: { topic, rowNumber: row.row_number || (i + 2), colA, colB, colC } }];
  }
}
throw new Error('No pending topics found in the Wady Topics sheet (column B must contain "pending").');

const raw = $input.first().json.text;
if (!raw) throw new Error('No content received from Gemini (English).');
let clean = raw.trim();
if (clean.startsWith('```')) {
  clean = clean.replace(/^```[a-z]*\n?/i, '').replace(/\n?```$/, '').trim();
}
const marker = '---BODY---';
const idx = clean.indexOf(marker);
if (idx === -1) throw new Error('English output is missing the ---BODY--- marker.');
const header = clean.slice(0, idx);
const body = clean.slice(idx + marker.length).trim();

function field(name) {
  const m = header.match(new RegExp('^' + name + ':\\s*(.+)$', 'mi'));
  return m ? m[1].trim() : '';
}

const validServices = ['website-design','search-engine-optimization','content-production','social-media-management','mobile-app-design','brand-identity','ecommerce-design','digital-marketing'];
let service = field('SERVICE').toLowerCase().replace(/[^a-z-]/g, '');
if (!validServices.includes(service)) service = 'content-production';

let readMin = parseInt(field('READTIME'), 10);
if (!readMin || readMin < 1) readMin = 8;

const ctx = $('Find First Pending Topic').first().json;
return [{ json: {
  topic: ctx.topic,
  rowNumber: ctx.rowNumber,
  colA: ctx.colA,
  colB: ctx.colB,
  colC: ctx.colC,
  service,
  enTitle: field('TITLE') || ctx.topic,
  enExcerpt: field('EXCERPT'),
  enDescription: field('DESCRIPTION'),
  enReadMin: readMin,
  enBody: body,
} }];

const raw = $input.first().json.text;
if (!raw) throw new Error('No content received from Gemini (Arabic).');
let clean = raw.trim();
if (clean.startsWith('```')) {
  clean = clean.replace(/^```[a-z]*\n?/i, '').replace(/\n?```$/, '').trim();
}
const marker = '---BODY---';
const idx = clean.indexOf(marker);
if (idx === -1) throw new Error('Arabic output is missing the ---BODY--- marker.');
const header = clean.slice(0, idx);
const body = clean.slice(idx + marker.length).trim();

function field(name) {
  const m = header.match(new RegExp('^' + name + ':\\s*(.+)$', 'mi'));
  return m ? m[1].trim() : '';
}

const en = $('Clean English Output').first().json;
let readMin = parseInt(field('READTIME'), 10);
if (!readMin || readMin < 1) readMin = en.enReadMin;

return [{ json: {
  ...en,
  arTitle: field('TITLE') || en.enTitle,
  arExcerpt: field('EXCERPT'),
  arDescription: field('DESCRIPTION'),
  arReadMin: readMin,
  arBody: body,
} }];

const d = $input.first().json;

// Map the AI-chosen service to its blog number + bilingual kicker (matches existing posts in the repo)
const SERVICES = {
  'website-design':             { num: 1, kicker: 'Design',            kickerAr: 'تصميم' },
  'search-engine-optimization': { num: 2, kicker: 'SEO',               kickerAr: 'سيو' },
  'content-production':         { num: 3, kicker: 'Content',           kickerAr: 'محتوى' },
  'social-media-management':    { num: 4, kicker: 'Social media',      kickerAr: 'سوشيال ميديا' },
  'mobile-app-design':          { num: 5, kicker: 'Mobile apps',       kickerAr: 'تطبيقات' },
  'brand-identity':             { num: 6, kicker: 'Brand identity',    kickerAr: 'هوية تجارية' },
  'ecommerce-design':           { num: 7, kicker: 'E-commerce',        kickerAr: 'تجارة إلكترونية' },
  'digital-marketing':          { num: 8, kicker: 'Digital marketing', kickerAr: 'تسويق إلكتروني' },
};
const svc = SERVICES[d.service] || SERVICES['content-production'];

// Dates (code node $now respects the instance timezone, Asia/Riyadh)
const now = $now;
const iso = now.toFormat('yyyy-MM-dd');
const enMonths = ['January','February','March','April','May','June','July','August','September','October','November','December'];
const arMonths = ['كانون الثاني','شباط','آذار','نيسان','أيار','حزيران','تموز','آب','أيلول','تشرين الأول','تشرين الثاني','كانون الأول'];
const y = now.year, mo = now.month, day = now.day;
const enDate = enMonths[mo - 1] + ' ' + day + ', ' + y;
const toAr = (n) => String(n).replace(/[0-9]/g, (ch) => '٠١٢٣٤٥٦٧٨٩'[ch]);
const arDate = toAr(day) + ' ' + arMonths[mo - 1] + ' ' + toAr(y);

const num = String(svc.num).padStart(2, '0');
const numAr = toAr(num);

const enRead = d.enReadMin + ' min';
const arUnit = (d.arReadMin >= 3 && d.arReadMin <= 10) ? 'دقائق' : 'دقيقة';
const arRead = toAr(d.arReadMin) + ' ' + arUnit;

// Wrap every text value in double quotes; the repo frontmatter parser strips one
// surrounding pair, so we replace any inner double quote with a typographic one.
const q = (s) => '"' + String(s == null ? '' : s).replace(/"/g, '’').replace(/\r?\n/g, ' ').trim() + '"';

const fm = [
  '---',
  'title: ' + q(d.enTitle),
  'titleAr: ' + q(d.arTitle),
  'excerpt: ' + q(d.enExcerpt),
  'excerptAr: ' + q(d.arExcerpt),
  'description: ' + q(d.enDescription),
  'descriptionAr: ' + q(d.arDescription),
  'num: ' + num,
  'numAr: ' + numAr,
  'kicker: ' + q(svc.kicker),
  'kickerAr: ' + q(svc.kickerAr),
  'date: ' + q(enDate),
  'dateAr: ' + q(arDate),
  'isoDate: ' + iso,
  'readTime: ' + q(enRead),
  'readTimeAr: ' + q(arRead),
  'serviceNum: ' + num,
  '---',
].join('\n');

// Defensive normalization: enforce the renderer's supported markdown subset
function normalize(md) {
  let t = (md || '').trim();
  t = t.replace(/^(\s*)\*\s+/gm, '$1- ');   // * bullets -> - bullets
  t = t.replace(/^#{3,}\s*/gm, '## ');        // ### or deeper -> ##
  t = t.replace(/\*\*(.+?)\*\*/g, '$1');      // strip **bold**
  return t.trim();
}
const enBody = normalize(d.enBody);
const arBody = normalize(d.arBody);
const fileBody = enBody + '\n\n<!-- AR -->\n\n' + arBody;
const fileContent = fm + '\n\n' + fileBody + '\n';

// Slug from the English title (<= 60 chars, no trailing hyphen)
let slug = (d.enTitle || d.topic).toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-|-$/g, '');
if (slug.length > 60) {
  const cut = slug.substring(0, 60);
  const lh = cut.lastIndexOf('-');
  slug = lh > 0 ? cut.substring(0, lh) : cut;
}
slug = slug.replace(/-$/, '') || ('post-' + iso);

return [{ json: {
  topic: d.topic,
  rowNumber: d.rowNumber,
  colA: d.colA,
  colB: d.colB,
  colC: d.colC,
  todayDate: iso,
  service: d.service,
  num,
  slug,
  articleTitle: d.enTitle,
  fileContent,
} }];

const t = $('Assemble Blog File').first().json;
const row = {};
row[t.colA] = t.topic;
row[t.colB] = 'used';
if (t.colC) row[t.colC] = t.todayDate;
return [{ json: row }];
